testbench:
`timescale 1ns/1ps
module tb;
  reg clk;
  reg areset_n;
  reg load;
  reg ena;
  reg [3:0] data;
  wire [3:0] q;

  shift4 dut(.clk(clk), .areset_n(areset_n), .load(load), .ena(ena), .data(data), .q(q));

  always #5 clk = ~clk;

  task step_check;
    input [3:0] expected;
    begin
      @(posedge clk);
      #1;
      if (q !== expected) begin
        $display("FAIL expected=%0b got=%0b", expected, q);
        $fatal(1);
      end
    end
  endtask

  initial begin
    clk = 0;
    areset_n = 1;
    load = 0;
    ena = 0;
    data = 4'b0000;

    #1;
    areset_n = 0;
    #1;
    if (q !== 4'b0000) begin
      $display("FAIL async reset expected=0000 got=%0b", q);
      $fatal(1);
    end

    areset_n = 1;
    load = 1;
    data = 4'b1011;
    step_check(4'b1011);

    load = 0;
    ena = 1;
    step_check(4'b0110);
    step_check(4'b1100);

    ena = 0;
    step_check(4'b1100);

    load = 1;
    data = 4'b0101;
    step_check(4'b0101);

    areset_n = 0;
    #1;
    if (q !== 4'b0000) begin
      $display("FAIL second async reset expected=0000 got=%0b", q);
      $fatal(1);
    end

    areset_n = 1;
    load = 0;
    ena = 1;
    step_check(4'b0000);

    $display("PASS");
    $finish;
  end
endmodule

reference_rtl:
module shift4(input clk, input areset_n, input load, input ena, input [3:0] data, output reg [3:0] q);
  always @(posedge clk or negedge areset_n) begin
    if (!areset_n)
      q <= 4'b0000;
    else if (load)
      q <= data;
    else if (ena)
      q <= {q[2:0], 1'b0};
  end
endmodule
